<template>
  <div class="fu-module-menu-wrapper scrollbar__control customScrollBar">
    <ul class="fu-module-menu-wrapper__list">
      <li
        v-for="item in items"
        :key="item.path"
        :class="{ active: activePath && activePath.startsWith(item.path) }"
      >
        <router-link class="fu-module-menu-link" :to="item.path">
          <component
            v-if="item.icon"
            :is="item.icon"
            :size="15"
            class="fu-module-menu-icon"
          />
          <span>{{ item.label }}</span>
        </router-link>
      </li>

      <li v-if="!items || !items.length" class="fu-module-menu-empty">No menu items</li>
    </ul>

    <!-- Custom slot after the list -->
    <slot />
  </div>
</template>

<script setup lang="ts">
import type { Component } from "vue";

interface MenuItem {
  label: string;
  path: string;
  icon?: Component;
}

defineProps<{
  items: MenuItem[];
  activePath?: string;
}>();
</script>

<style scoped lang="scss">
@import url("./FusionModuleMenu.scss");
</style>
